    // Declare variables to store the two numbers
    double num1, num2;
    string input;

    // Display a clear instruction to the user
    cout << "Please enter two numbers and I will display their sum." << endl;
    cout << "Enter the first number: ";

    // Loop to handle invalid input for the first number
    while (true) {
        getline(cin, input);
        try {
            num1 = stod(input); // Convert string to double
            break; // Exit the loop if conversion is successful
        } catch (invalid_argument&) {
            cout << "Invalid input. Please enter a numeric value." << endl;
            cout << "Enter the first number: ";
        }
    }

    // Loop to handle invalid input for the second number
    cout << "Enter the second number: ";
    while (true) {
        getline(cin, input);
